const techLogoComponents: Record<TechLogoName, (props: SVGProps<SVGSVGElement>) => ReactNode> = {
	react: ReactIcon,
	bun: BunIcon,
	typescript: TypeScriptIcon,
	"react-router": ReactRouterIcon,
	shadcn: ShadcnIcon,
	"better-auth": BetterAuthIcon,
	tanstack: TanStackIcon,
	google: GoogleIcon,
	github: GitHubIcon,
	drizzle: DrizzleIcon,
	sqlite: SQLiteIcon,
	"module-federation": ModuleFederationIcon,
};

const techLogoLabels: Record<TechLogoName, string> = {
	react: "React",
	bun: "Bun",
	typescript: "TypeScript",
	"react-router": "React Router",
	shadcn: "shadcn/ui",
	"better-auth": "Better Auth",
	tanstack: "TanStack",
	google: "Google",
	github: "GitHub",
	drizzle: "Drizzle ORM",
	sqlite: "SQLite",
	"module-federation": "Module Federation",
};

export function TechLogo({
	name,
	className,
	style,
}: {
	name: TechLogoName;
	className?: string;
	style?: CSSProperties;
}) {
	const Icon = techLogoComponents[name];
	const label = techLogoLabels[name];

	return (
		<Icon
			aria-label={label}
			className={cn("h-4 w-4 shrink-0 object-contain", className)}
			style={style}
		/>
	);
}

export function TechPill({ name, className }: { name: TechLogoName; className?: string }) {
	const label = techLogoLabels[name];

	return (
		<div
			className={cn(
				"inline-flex items-center gap-2 rounded-lg border border-border/60 bg-card/90 px-3 py-1.5 text-xs font-medium text-foreground shadow-sm shadow-black/[0.03]",
				className,
			)}
		>
			<TechLogo name={name} />
			<span>{label}</span>
		</div>
	);
}
